import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import "./Dashboard.css";

function Dashboard() {
  const navigate = useNavigate();

  const [searchTerm, setSearchTerm] = useState("");
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);

  // 🔥 ambil data dari backend
  useEffect(() => {
    fetch("http://localhost:5000/products")
      .then((res) => res.json())
      .then((data) => {
        setBooks(data);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Gagal ambil produk:", err);
        setLoading(false);
      });
  }, []);

  const filteredBooks = books.filter((book) =>
    book.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    book.author?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    book.category_name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleLogout = () => {
    navigate("/");
  };

  return (
    <div className="dashboard-container">
      <div className="dashboard-header">
        <div className="header-content">
          <h1>📚 Toko Buku Cerita Anak Indonesia</h1>
          <p>SELAMAT DATANG BOSQUUUU</p>
        </div>
        <button className="logout-btn" onClick={handleLogout}>
          🚪 Logout
        </button>
      </div>

      <div className="books-section">
        <div className="books-header">
          <h2>📚 Koleksi Cerita Nusantara</h2>
          <input
            type="text"
            className="search-box"
            placeholder="🔍 Cari judul, penulis, atau kategori..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {loading ? (
          <p>⏳ Loading buku...</p>
        ) : (
          <p className="search-result">
            Menampilkan {filteredBooks.length} dari {books.length} buku
          </p>
        )}

        <div className="books-grid">
          {!loading && filteredBooks.length > 0 ? (
            filteredBooks.map((book) => (
              <div key={book.id} className="book-card">
                <div className="book-image">
                  <img
                    src={book.image || "/images/default.jpg"}
                    alt={book.title}
                    className="book-cover"
                  />
                  <span className="category-badge">
                    {book.category_name}
                  </span>
                </div>

                <div className="book-info">
                  <h3>{book.title}</h3>
                  <p className="author">✍️ {book.author}</p>
                  <div className="book-footer">
                    <span className="price">
                      Rp {Number(book.price).toLocaleString("id-ID")}
                    </span>
                    <button className="add-btn">🛒 Beli</button>
                  </div>
                </div>
              </div>
            ))
          ) : (
            !loading && <p>📭 Buku tidak ditemukan</p>
          )}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
